#!/system/bin/sh
set -u
ROOT=/data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h
BASE_RUN_ID=20260524T210920Z_phase13_gemma4_only_heterogeneous_p13h_20260524T232423Z
RUN_ID=20260524T210920Z_phase13_gemma4_only_heterogeneous_p13h_20260524T232423Z_fullheldout
RUNNER=/data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/bin/phase11_runner
LAYER_RUNNER=/data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/bin/gemma4_layer_runner
ORIGINAL_STATE=/data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/p13h_20260524T210920Z_phase13_gemma4_only_heterogeneous_p13h_20260524T232423Z_chain_state.json
ORIGINAL_EVENTS=/data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/p13h_20260524T210920Z_phase13_gemma4_only_heterogeneous_p13h_20260524T232423Z_chain_events.jsonl
TRAIN_FINAL_MANIFEST=/data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/runs/20260524T210920Z_phase13_gemma4_only_heterogeneous_p13h_20260524T232423Z_train/P13-H-overnight-phone-local-long-run/iterations/iter_004999/checkpoint/manifest.json
SAFETY_LOG=/data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/p13h_20260524T210920Z_phase13_gemma4_only_heterogeneous_p13h_20260524T232423Z_fullheldout_safety.jsonl
LOG="$ROOT/p13h_${RUN_ID}_full_heldout_chain.log"
EVENTS="$ROOT/p13h_${RUN_ID}_full_heldout_chain_events.jsonl"
STATE="$ROOT/p13h_${RUN_ID}_full_heldout_chain_state.json"
STOP="$ROOT/STOP_p13h_full_heldout_chain_${RUN_ID}"
BOOTSTRAP="$ROOT/p13h_${RUN_ID}_full_heldout_chain.bootstrap.log"
write_state() { printf '{"schema_version":"phase13_p13h_full_heldout_chain_state_v1","run_id":"%s","status":"%s","step":"%s","updated_at_epoch":%s}\n' "$RUN_ID" "$1" "$2" "$(date +%s)" > "$STATE"; }
write_event() { printf '{"schema_version":"phase13_p13h_full_heldout_chain_event_v1","step":"%s","status":"%s","returncode":%s,"updated_at_epoch":%s}\n' "$1" "$2" "$3" "$(date +%s)" >> "$EVENTS"; }
thermal_monitor() { while true; do TS="$(date +%s)"; BAT="$(dumpsys battery 2>/dev/null | awk '/temperature:/ {print $2; exit}')"; MAX=0; MAXTYPE=unknown; for z in /sys/class/thermal/thermal_zone*; do [ -r "$z/temp" ] || continue; T="$(cat "$z/temp" 2>/dev/null)"; Y="$(cat "$z/type" 2>/dev/null)"; case "$T" in -*) continue;; ""|*[!0-9]*) continue;; esac; if [ "$T" -gt "$MAX" ]; then MAX="$T"; MAXTYPE="$Y"; fi; done; printf '{"ts":%s,"battery_tenth_c":"%s","max_zone_millideg_c":%s,"max_zone_type":"%s"}\n' "$TS" "$BAT" "$MAX" "$MAXTYPE" >> "$SAFETY_LOG"; if [ -n "$BAT" ] && [ "$BAT" -ge 460 ]; then touch "$STOP" "$ROOT"/STOP_p13h_full_*; exit 0; fi; if [ "$MAX" -ge 92000 ]; then touch "$STOP" "$ROOT"/STOP_p13h_full_*; exit 0; fi; sleep 30; done; }
wait_for_training() { write_state waiting original_train_completion; while true; do if [ -f "$STOP" ]; then write_state stopped wait_for_training; write_event wait_for_training stopped 130; exit 130; fi; if [ -f "$TRAIN_FINAL_MANIFEST" ]; then if grep -q '"status":"completed"' "$ORIGINAL_STATE" 2>/dev/null; then write_event wait_for_training pass 0; return 0; fi; if grep -q '"status":"failed"' "$ORIGINAL_STATE" 2>/dev/null; then write_event wait_for_training original_failed_after_checkpoint 0; return 0; fi; fi; if grep -q '"status":"failed"' "$ORIGINAL_STATE" 2>/dev/null && [ ! -f "$TRAIN_FINAL_MANIFEST" ]; then write_state failed original_failed_before_train_checkpoint; write_event wait_for_training failed 1; exit 1; fi; if grep -q '"status":"stopped"' "$ORIGINAL_STATE" 2>/dev/null; then write_state stopped original_stopped; write_event wait_for_training stopped 130; exit 130; fi; sleep 300; done; }
run_step() { STEP="$1"; shift; if [ -f "$STOP" ]; then write_state stopped "$STEP"; write_event "$STEP" stopped 130; exit 130; fi; write_state running "$STEP"; "$@" >> "$LOG" 2>&1; RC="$?"; if [ "$RC" -eq 0 ]; then STATUS=pass; else STATUS=fail; fi; write_event "$STEP" "$STATUS" "$RC"; if [ "$RC" -ne 0 ]; then write_state failed "$STEP"; exit "$RC"; fi; }
rm -f "$EVENTS" "$LOG" "$STATE" "$BOOTSTRAP" "$SAFETY_LOG" "$STOP"
rm -f "$ROOT"/STOP_p13h_heldout_full_baseline "$ROOT"/STOP_p13h_heldout_full_trained
thermal_monitor & MONITOR_PID=$!
wait_for_training
run_step post_train_g1_layer0_opencl_smoke "$LAYER_RUNNER" --run-opencl /data/local/tmp/polymath_gemma4_gate/layer_pack/gemma4_e4b_layer0_seq128_v0 "$ROOT/preflight/full_heldout_g1_layer0_opencl_smoke"
run_step post_train_g3_two_layer_opencl_stack_smoke "$LAYER_RUNNER" --run-opencl-stack /data/local/tmp/polymath_gemma4_gate/layer_pack/gemma4_e4b_layer0_seq128_v0 /data/local/tmp/polymath_gemma4_gate/layer_pack/gemma4_e4b_layer1_seq128_v0 "$ROOT/preflight/full_heldout_g3_two_layer_opencl_stack_smoke"
run_step heldout_full_baseline sh -c 'cd /data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h; /data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/bin/phase11_runner --queue queue/p13h_heldout_full_baseline_queue.jsonl --run-root runs --heartbeat /data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/p13h_heldout_full_baseline_heartbeat.json --state /data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/p13h_heldout_full_baseline_state.json --stop-file /data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/STOP_p13h_heldout_full_baseline'
run_step heldout_full_trained sh -c 'cd /data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h; /data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/bin/phase11_runner --queue queue/p13h_heldout_full_trained_queue.jsonl --run-root runs --heartbeat /data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/p13h_heldout_full_trained_heartbeat.json --state /data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/p13h_heldout_full_trained_state.json --stop-file /data/local/tmp/polymath_gemma4_gate/phase13/20260524T210920Z_phase13_gemma4_only_heterogeneous/p13h/STOP_p13h_heldout_full_trained'
kill "$MONITOR_PID" 2>/dev/null || true
write_state completed done
exit 0
